import React, { useState, useEffect } from 'react';
import '../App.css';

const sliderData = [
  {
    title: "Fast Food Restaurant",
    description: "Doloremque, itaque aperiam facilis rerum, commodi, temporibus sapiente ad mollitia laborum quam quisquam esse error unde.",
    image: "/image/hero-bg.jpg" // Slide 1 Image
  },
  {
    title: "Delicious Pizza",
    description: "Veniam debitis quaerat officiis quasi cupiditate quo, nihil gubergren, eos natus lead architecto.",
    image: "/image/pizza-slide.png" // Replace with your 2nd image
  },
  {
    title: "Tasty Pasta",
    description: "Explicabo esse amet tempora quibusdam laudantium, ratione eaque omnis id delectus ducimus.",
    image: "/image/pasta-slide.png" // Replace with your 3rd image
  }
];

const Hero = () => {
  const [current, setCurrent] = useState(0);

  // Auto-move slider every 5 seconds
  useEffect(() => {
    const next = (current + 1) % sliderData.length;
    const id = setTimeout(() => setCurrent(next), 5000);
    return () => clearTimeout(id);
  }, [current]);

  return (
    <div className="hero_area">
      <div className="bg-box">
        <img src="/image/hero-bg.jpg" alt="" />
      </div>

      <header className="header_section">
        <div className="container">
          <nav className="navbar">
            <a className="navbar-brand" href="/"><span>Feane</span></a>
            <div className="user_option">
              <a href="#"><i className="fa fa-user"></i></a>
              <a href="#"><i className="fa fa-shopping-cart"></i></a>
              <a href="#"><i className="fa fa-search"></i></a>
              <button className="order_online">Order Online</button>
            </div>
          </nav>
        </div>
      </header>

      <section className="slider_section">
        <div className="container">
          <div className="row">
            {/* The Key: We use the 'current' index to show data */}
            <div className="detail-box fade-in" key={current}>
              <h1>{sliderData[current].title}</h1>
              <p>{sliderData[current].description}</p>
              <div className="btn-box">
                <a href="" className="btn1">Order Now</a>
              </div>
            </div>
            
            <div className="img-box fade-in" key={`img-${current}`}>
              <img src={sliderData[current].image} alt="food" />
            </div>
          </div>
          
          <div className="slider_indicators">
            {sliderData.map((_, index) => (
              <span 
                key={index}
                className={`dot ${current === index ? 'active-dot' : ''}`}
                onClick={() => setCurrent(index)} // Allow clicking dots to move
              ></span>
            ))}
          </div>
        </div>
      </section>
    </div>
  );
};

export default Hero;
